import React, { Component } from 'react';
import { Link, withRouter } from 'react-router-dom';
import { connect } from 'react-redux';
import PropTypes from 'prop-types';
import cloneDeep from 'lodash.clonedeep';
import $ from 'jquery';
import s from '../Auth.module.scss';
import ReactLoading from 'react-loading';
import Icon from '../../../Icons/base';

import { registerUser } from '../../../../redux/actions/authentication';

class Signup extends Component {

    constructor(props) {
        super(props);
        this.state = {
            first_name: "",
            last_name: "",
            email: "",
            username: "",
            password: "",
            waiting: false,
            success: false
        };

        this.handleInputChange = this.handleInputChange.bind(this);
        this.submitForm = this.submitForm.bind(this);

        if (props.auth.isAuthenticated) {
            props.history.push('/');
        }
    }



    UNSAFE_componentWillReceiveProps(newProps) { 
        console.log(newProps);

        if (Object.entries(newProps.errors).length !== 0) {
            this.setState({ errors: newProps.errors, waiting: false });
        } else {
            this.setState({ waiting: false, success: true });
        }
    }

    handleInputChange(e) {
        const current_target = [e.target.name].toString();
        this.setState({ [e.target.name]: e.target.value });

        const errors = this.state.errors;   
        if (errors !== undefined) {
            this.setState(prevState => ({
                errors: {     
                    ...prevState.errors, 
                    [current_target]: '',
                    general: ""
                }
            }))
        }
    }

    triggerFocus(e) {
        $(e.target).parent().addClass(s['form-group--active']);
    }

    removeFocus(e) {
        if (e.target.value == "") {
            $(e.target).parent().removeClass(s['form-group--active']);
        }
    }

    submitForm(e) {
        e.preventDefault();
        const user = {
            first_name: this.state.first_name,
            last_name: this.state.last_name,
            email: this.state.email,
            username: this.state.username,
            password: this.state.password
        }
        this.props.registerUser(user);
        this.setState({ waiting: true });
    }

    render() { 

        const { errors, waiting, success } = this.state;

        return (
            <div className={s.background}>
                <div className={s.form}>
                    <div className={s.header}>
                        <h3>Sign up</h3>
                        <Link to="/">Artly</Link>
                    </div>
                    {success ? <div className={s['form-group__success']}>
                        <div className={s['form-group__success--flex']}>
                            <Icon name="checkmarkcircle"/>
                            <p>Success! We've sent you verifaction code to your email address.</p>
                        </div>
                        <div className={s['form-group__success--btn']}>
                            <Link to="/login" className="bs-btn bs-btn--rounded bs-btn--primary">Log in now.</Link>
                        </div>
                    </div> : 
                    <form onSubmit={this.submitForm} autoComplete="none">
                        <div className={[s['form-group'], s['form-group-two']].join(' ')}>
                            <div className={s['form-group-two__item']}>
                                <input 
                                    type="text"
                                    name="first_name" 
                                    autoComplete="off"
                                    onChange={this.handleInputChange}
                                    onFocus={this.triggerFocus}
                                    onBlur={this.removeFocus}
                                    value={this.state.first_name}
                                    className="bs-input"
                                />
                                <span>First name</span>
                                {(errors !== undefined && errors.first_name !== '') ? <p className={s['form-error']}>{errors.first_name}</p> : ''}
                            </div>  
                            <div className={s['form-group-two__item']}>
                                <input 
                                    type="text"
                                    name="last_name" 
                                    autoComplete="off"
                                    onChange={this.handleInputChange}
                                    onFocus={this.triggerFocus}
                                    onBlur={this.removeFocus}
                                    value={this.state.last_name}
                                    className="bs-input"
                                />
                                <span>Last name</span>
                                {(errors !== undefined && errors.last_name !== '') ? <p className={s['form-error']}>{errors.last_name}</p> : ''}
                            </div>
                        </div>
                        <div className={s['form-group']}>
                            <input
                                type="email"
                                name="email"
                                autoComplete="off"
                                onChange={this.handleInputChange}
                                onFocus={this.triggerFocus}
                                onBlur={this.removeFocus}
                                value={this.state.email}
                                className='bs-input'
                            />
                            <span>Email address</span>
                            {(errors !== undefined && errors.email !== '') ? <p className={s['form-error']}>{errors.email}</p> : ''}
                        </div>
                        <div className={s['form-group']}>
                            <input
                                type="text"
                                name="username"
                                autoComplete="off"
                                onChange={this.handleInputChange}
                                onFocus={this.triggerFocus}
                                onBlur={this.removeFocus}
                                value={this.state.username}
                                className='bs-input'
                            />
                            <span>Username</span>
                            {(errors !== undefined && errors.username !== '') ? <p className={s['form-error']}>{errors.username}</p> : ''}
                        </div>
                        <div className={s['form-group']}>
                            <input
                                type="password"
                                name="password"
                                autoComplete="off"
                                onChange={this.handleInputChange}
                                onFocus={this.triggerFocus}
                                onBlur={this.removeFocus}
                                value={this.state.password}
                                className='bs-input'
                            />
                            <img src=""/>
                            <span>Password</span>
                            {(errors !== undefined && errors.password !== '') ? <p className={s['form-error']}>{errors.password}</p> : ''}
                            {(errors !== undefined && errors.general !== '') ? <p className={s['form-error']}>{errors.general}</p> : ''}
                        </div>
                        <div className={[s['form-group'], s['form-group__submit']].join(' ')}>
                            <button type="submit" disabled={this.state.waiting}>{waiting ? <ReactLoading type="bars" color="#ffffff" height="auto" width="auto" /> : "Create account"}</button>
                        </div>
                        <div className={s['form-group__final']}>
                            <p>Already have an account? <Link to="/login">Log in.</Link></p>
                        </div>
                        <div className={[s['form-group'], s['form-group__additional-text']].join(' ')}>
                            <p>By registering, you accept the Regulations. Information on how we collect, use and share your data is included in our Data Policies. Cookie Policy informs you about the use of cookies and similar technologies.</p>
                        </div>
                    </form> }
                </div>
            </div>
        )
    }
}

Signup.propTypes = {
    auth: PropTypes.object,
    registerUser: PropTypes.func,
    errors: PropTypes.object.isRequired,
    history: PropTypes.object.isRequired
};

const mapStateToProps = (state) => ({
    auth: state.auth,
    errors: state.errors
});

export default withRouter(connect(mapStateToProps, { registerUser })(Signup));
